50	  FabricTileId find_tile_by_cb_coordinate(
51	    const e_rr_type& cb_type, const vtr::Point<size_t>& coord) const;
52	  /** @brief Find the id of a tile, with a given coordinate of the switch block
53	   * under the tile */
54	  FabricTileId find_tile_by_sb_coordinate(
55	    const vtr::Point<size_t>& coord) const;
56	  /** @brief Find the coordinate of the unique tile w.r.t the tile with a tile
57	   * id */
58	  vtr::Point<size_t> unique_tile_coordinate(const FabricTileId& tile_id) const;
59	  /** @brief Return a list of unique tiles */
60	  std::vector<FabricTileId> unique_tiles() const;
61	  /** @brief Find the index of a programmable block in the internal list by a
62	   * given coordinate. Note that the coord can be either the one in device grid
63	   * or the one of gsb which the programmable block belongs to  */
64	  size_t find_pb_index_in_tile(const FabricTileId& tile_id,
65	                               const vtr::Point<size_t>& coord,
