120	  /* Set the top-right coordinate of a pb. This is mainly for heterogeneous
121	   * blocks, whose height or width can be > 1 */
122	  int set_pb_max_coordinate(const FabricTileId& tile_id, const size_t& pb_index,
123	                            const vtr::Point<size_t>& max_coord);
124	  int add_cb_coordinate(const FabricTileId& tile_id, const e_rr_type& cb_type,
125	                        const vtr::Point<size_t>& coord);
126	  int add_sb_coordinate(const FabricTileId& tile_id,
127	                        const vtr::Point<size_t>& coord);
128	  /** @brief Build a list of unique tiles by comparing the coordinates in
129	   * DeviceRRGSB */
130	  void build_unique_tiles();
131	  /** @brief Clear all the content */
132	  void clear();
133	  /** @brief Initialize the data with a given range. Used by constructors */
134	  void init(const vtr::Point<size_t>& max_coord);
135	  /** @brief Identify the number of unique tiles and keep in the lookup */
136	  int build_unique_tiles(const DeviceGrid& grids,
137	                         const DeviceRRGSB& device_rr_gsb, const bool& verbose);
138	
139	 public: /* Validators */
140	  bool valid_tile_id(const FabricTileId& tile_id) const;
141	
142	 private: /* Internal validators */
143	  /** @brief Identify if two tile are equivalent in their sub-modules, including
144	   * pb, cbx, cby and sb */
145	  bool equivalent_tile(const FabricTileId& tile_a, const FabricTileId& tile_b,
146	                       const DeviceGrid& grids,
147	                       const DeviceRRGSB& device_rr_gsb) const;
148	
149	 private: /* Internal builders */
150	  void invalidate_tile_in_lookup(const vtr::Point<size_t>& coord);
151	  void invalidate_pb_in_lookup(const vtr::Point<size_t>& coord);
152	  void invalidate_cbx_in_lookup(const vtr::Point<size_t>& coord);
153	  void invalidate_cby_in_lookup(const vtr::Point<size_t>& coord);
154	  void invalidate_sb_in_lookup(const vtr::Point<size_t>& coord);
155	  bool register_tile_in_lookup(const FabricTileId& tile_id,
156	                               const vtr::Point<size_t>& coord);
