1	/********************************************************************
2	 * This file includes functions that are used to annotate device-level
3	 * information, in particular the routing resource graph
4	 *******************************************************************/
5	#include <algorithm>
6	#include <unordered_set>
7	
8	/* Headers from vtrutil library */
9	#include "vtr_assert.h"
10	#include "vtr_log.h"
11	#include "vtr_time.h"
12	
13	/* Headers from openfpgautil library */
14	#include "side_manager.h"
15	
16	/* Headers from vpr library */
17	#include "annotate_rr_graph.h"
18	#include "openfpga_rr_graph_utils.h"
19	#include "physical_types.h"
20	#include "rr_graph_in_edges.h"
21	#include "rr_graph_view.h"
22	#include "rr_graph_view_util.h"
23	#include "rr_gsb_edges.h"
24	#include "tileable_rr_graph_utils.h"
25	
26	/* begin namespace openfpga */
27	namespace openfpga {
28	
29	/*********************************************************************
30	 * Find a list of rr_nodes that locate at a side of a grid
31	 **********************************************************************/
32	static std::vector<RRNodeId> openfpga_find_rr_graph_grid_nodes(
33	  const RRGraphView& rr_graph, const DeviceGrid& device_grid,
34	  const size_t& layer, const int& x, const int& y, const e_rr_type& rr_type,
35	  const e_side& side, bool include_ignored_global_pins) {
36	  std::vector<RRNodeId> indices;
37	
38	  VTR_ASSERT(rr_type == e_rr_type::IPIN || rr_type == e_rr_type::OPIN);
39	
40	  /* Ensure that (x, y) is a valid location in grids */
41	  if (size_t(x) > device_grid.width() - 1 ||
42	      size_t(y) > device_grid.height() - 1) {
43	    return indices;
44	  }
45	
46	  /* Ensure we have a valid side */
47	  VTR_ASSERT(side != NUM_2D_SIDES);
48	
49	  /* Find all the pins on the side of the grid */
50	  t_physical_tile_loc tile_loc(x, y, layer);
51	  int width_offset = device_grid.get_width_offset(tile_loc);
52	  int height_offset = device_grid.get_height_offset(tile_loc);
53	
54	  for (int pin = 0; pin < device_grid.get_physical_type(tile_loc)->num_pins;
55	       ++pin) {
56	    /* Skip those pins have been ignored during rr_graph build-up */
57	    if (device_grid.get_physical_type(tile_loc)->is_ignored_pin[pin] &&
58	        device_grid.get_physical_type(tile_loc)->is_pin_global[pin]) {
59	      /* If specified, force to include all the ignored pins */
60	      if (!include_ignored_global_pins) {
61	        continue;
62	      }
63	    }
64	    if (false == device_grid.get_physical_type(tile_loc)
65	                   ->pinloc[width_offset][height_offset][side][pin]) {
66	      /* Not the pin on this side, we skip */
67	      continue;
68	    }
69	
70	    /* Try to find the rr node */
